import { useEffect, useState } from "react";
import socket from "../socket";

function Player() {
  const [name, setName] = useState("");
  const [joined, setJoined] = useState(false);

  const [question, setQuestion] = useState(null);
  const [score, setScore] = useState(0);

  // ✅ SOCKET LISTENERS
  useEffect(() => {
    // 🔌 Connected
    socket.on("connect", () => {
      console.log("✅ Connected:", socket.id);
    });

    // 🎮 Game started
    socket.on("gameStarted", (q) => {
      console.log("Game started:", q);
      setQuestion(q);
    });

    // 👉 Next question
    socket.on("nextQuestion", (q) => {
      console.log("Next question:", q);
      setQuestion(q);
    });

    // 🏆 Score update
    socket.on("scoreUpdated", (scores) => {
      console.log("Scores:", scores);

      // If your score is tracked by name
      if (scores[name] !== undefined) {
        setScore(scores[name]);
      }
    });

    return () => {
      socket.off("connect");
      socket.off("gameStarted");
      socket.off("nextQuestion");
      socket.off("scoreUpdated");
    };
  }, [name]);

  // ✅ JOIN GAME
  const joinGame = () => {
    if (!name) {
      alert("Enter your name");
      return;
    }

    console.log("Joining:", name);

    socket.emit("joinGame", name); // 🔥 MUST MATCH BACKEND
    setJoined(true);
  };

  // ✅ ANSWER QUESTION
  const sendAnswer = (option) => {
    if (!question) return;

    const isCorrect = option === question.answer;

    socket.emit("answer", {
      name,
      correct: isCorrect,
    });
  };

  // ❌ BEFORE JOIN
  if (!joined) {
    return (
      <div style={{ padding: "20px" }}>
        <h2>Enter your name</h2>

        <input
          type="text"
          placeholder="Your name"
          value={name}
          onChange={(e) => setName(e.target.value)}
        />

        <br /><br />

        <button onClick={joinGame}>Join Game</button>
      </div>
    );
  }

  // ✅ AFTER JOIN
  return (
    <div style={{ padding: "20px" }}>
      <h2>Player: {name}</h2>

      {question ? (
        <div>
          <h3>{question.question}</h3>

          {question.options.map((opt, i) => (
            <button
              key={i}
              onClick={() => sendAnswer(opt)}
              style={{ display: "block", margin: "10px" }}
            >
              {opt}
            </button>
          ))}
        </div>
      ) : (
        <p>Waiting for host...</p>
      )}

      <h3>Score: {score}</h3>
    </div>
  );
}

export default Player;
